// Combine scraped pages into one trimmed text blob for the LLM
const items = $input.all();
let combined = '';
for (const it of items) {
  const j = it.json || {};
  const md = j.markdown || j.text || '';
  if (md) combined += md + '\n\n---\n\n';
}
// Trim to keep token cost sane (~6000 chars ≈ enough signal)
combined = combined.replace(/\n{3,}/g, '\n\n').slice(0, 6000);

// Carry forward the original lead row from the loop
const lead = $('Loop Through Leads').item.json;

if (!combined || combined.trim().length < 50) {
  return [{ json: { ...lead, scrapeOk: false, siteText: '' } }];
}
return [{ json: { ...lead, scrapeOk: true, siteText: combined } }];

// Parse analysis JSON safely + decide A/B framing
const lead = $('Loop Through Leads').item.json;

// "Message a model" node nests text deep — check all known shapes
let analysisRaw =
  $json.output?.[0]?.content?.[0]?.text   // Message a model (Responses API)
  ?? $json.message?.content                // classic OpenAI node
  ?? $json.choices?.[0]?.message?.content  // chat completions
  ?? $json.text
  ?? $json.content
  ?? '{}';

if (typeof analysisRaw === 'object') analysisRaw = JSON.stringify(analysisRaw);

// Strip code fences if model wrapped it
analysisRaw = String(analysisRaw).replace(/```json|```/g, '').trim();

let analysis = {};
try { analysis = JSON.parse(analysisRaw); }
catch(e) { analysis = { practice_summary:'', observations:[], top_angle:'' }; }

// A/B framing: alternate soft vs direct
const idx = $('Loop Through Leads').context?.currentRunIndex ?? 0;
const framing = (idx % 2 === 0) ? 'soft' : 'direct';

return [{ json: { ...lead, analysis, analysisJson: JSON.stringify(analysis), framing } }];

const lead = $('Loop Through Leads').item.json;
let raw =
  $json.output?.[0]?.content?.[0]?.text
  ?? $json.message?.content
  ?? $json.choices?.[0]?.message?.content
  ?? $json.text ?? $json.content ?? '{}';
if (typeof raw === 'object') raw = JSON.stringify(raw);
raw = String(raw).replace(/```json|```/g, '').trim();
let draft = {};
try { draft = JSON.parse(raw); } catch(e) { draft = { subject:'', body:'' }; }

const subject = draft.subject || 'Quick idea for your practice';
const body = draft.body || '';
const full = `Subject: ${subject}\n\n${body}`;

const a = $('Decide Email Framing').item.json.analysis || {};
const notes = a.practice_summary || '';
const weak = (a.observations || []).map(o => `• ${o.area}: ${o.finding}`).join('\n');

return [{ json: { ...lead, ScrapedNotes: notes, WeakPoints: weak, DraftEmail: full, Status: 'drafted' } }];

